const CACHE_NAME="turni-in-pista-cache-v1",FILES_TO_CACHE=["./","./index.html","./index.min.html","./manifest.json","./icon-192.png","./icon-512.png"];self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE_NAME).then(a=>a.addAll(FILES_TO_CACHE))),self.skipWaiting()});self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(a=>Promise.all(a.map(b=>b!==CACHE_NAME&&caches.delete(b))))),self.clients.claim()});self.addEventListener("fetch",e=>{e.respondWith(caches.match(e.request).then(a=>a||fetch(e.request).catch(()=>{"navigate"===e.request.mode&&caches.match("./index.html")})))});
